set-variable.value:
#[%dw 2.0
output application/java

var acc = vars.accountNumber
var record = (payload filter ($.ACCOUNTNUMBER == acc))[0] default {}

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>

body{
    margin:0;
    padding:0;
    background:#f2f5f9;
    font-family:Arial,Helvetica,sans-serif;
}

.wrapper{
    width:100%;
    padding:35px 0;
}

.container{
    width:650px;
    margin:auto;
    background:#ffffff;
    border-radius:15px;
    overflow:hidden;
    box-shadow:0 10px 35px rgba(0,0,0,.15);
}

.header{
    background:linear-gradient(90deg,#003366,#0059b3);
    padding:30px;
    color:#fff;
    text-align:center;
}

.logo{
    font-size:30px;
    font-weight:bold;
}

.tagline{
    margin-top:8px;
    font-size:14px;
    opacity:.9;
}

.alert{
    text-align:center;
    padding:35px 25px;
}

.icon{
    width:85px;
    height:85px;
    line-height:85px;
    border-radius:50%;
    margin:auto;
    background:#ef4444;
    color:#fff;
    font-size:42px;
}

.alert h2{
    color:#dc2626;
    margin-top:20px;
}

.message{
    color:#555;
    font-size:15px;
}

.summary{
    margin:25px;
    border:1px solid #e5e7eb;
    border-radius:10px;
    overflow:hidden;
}

.summary-header{
    background:#f8fafc;
    padding:15px;
    font-size:20px;
    font-weight:bold;
    color:#003366;
}

table{
    width:100%;
    border-collapse:collapse;
}

td{
    padding:15px;
    border-bottom:1px solid #ececec;
}

.label{
    font-weight:bold;
    color:#555;
}

.value{
    text-align:right;
    color:#111827;
}

.amount{
    color:#dc2626;
    font-size:22px;
    font-weight:bold;
}

.status{
    color:#16a34a;
    font-weight:bold;
}

.notice{
    margin:25px;
    background:#fff8e6;
    border-left:5px solid #f59e0b;
    padding:18px;
    color:#555;
    border-radius:6px;
}

.footer{
    background:#f8fafc;
    text-align:center;
    padding:30px;
    color:#666;
    font-size:13px;
}

.footer a{
    color:#0059b3;
    text-decoration:none;
}

</style>

</head>

<body>

<div class='wrapper'>

<div class='container'>

<div class='header'>

<div class='logo'>
🏦 " ++ (vars.BANKNAME default "N/A") ++ "
</div>

<div class='tagline'>
Secure • Trusted • Digital Banking
</div>

</div>

<div class='alert'>

<div class='icon'>
⬇
</div>

<h2>Debit Transaction Successful</h2>

<p class='message'>
A withdrawal has been successfully processed from your account.
</p>

</div>

<div class='summary'>

<div class='summary-header'>
Transaction Details
</div>

<table>

<tr>
<td class='label'>Transaction ID</td>
<td class='value'>" ++ (vars.transactionId default "N/A") ++ "</td>
</tr>

<tr>
<td class='label'>Account Number</td>
<td class='value'>" ++ (vars.accountNumber as String) ++ "</td>
</tr>

<tr>
<td class='label'>Transaction Type</td>
<td class='value'>WITHDRAW</td>
</tr>

<tr>
<td class='label'>Amount Debited</td>
<td class='value amount'>
₹" ++ ((vars.amount default 0) as String) ++ "
</td>
</tr>

<tr>
<td class='label'>Available Balance</td>
<td class='value'>
₹" ++ ((record.BALANCE default 0) as String) ++ "
</td>
</tr>

<tr>
<td class='label'>Transaction Date</td>
<td class='value'>
" ++ ((now()) as String {format:'dd MMM yyyy hh:mm:ss a'}) ++ "
</td>
</tr>

<tr>
<td class='label'>Status</td>
<td class='value status'>
SUCCESS
</td>
</tr>

</table>

</div>

<div class='notice'>

<b>Security Advice</b><br/><br/>

If you did not authorize this transaction, immediately contact our 24×7 Customer Care or temporarily block your debit card through Internet Banking or the Mobile Banking App.

</div>

<div class='footer'>

<b>Real Bank</b><br/><br/>

📞 Customer Care : +91 9494207062<br/>

✉ support@realbank.com<br/>

🌐 www.realbank.com<br/><br/>

© 2026 Real Bank. All Rights Reserved.<br/><br/>

This is an automated transaction alert. Please do not reply to this email.

</div>

</div>

</div>

</body>

</html>"]
